func streamStockQuotes(tickers []string, interval time.Duration) {
	stockChan := make(chan StockData)
	var wg sync.WaitGroup
	stats := make(map[string]*StockStats)
	var statsMutex sync.Mutex

	// Start goroutines for each ticker
	for _, ticker := range tickers {
		wg.Add(1)
		go func(t string) {
			defer wg.Done()
			for {
				price := generateRandomPrice(t) // Replace with actual price source
				stockChan <- StockData{Ticker: t, Price: price}
				time.Sleep(time.Millisecond * 100) // Simulate delay between updates
			}
		}(ticker)
	}

	// Start goroutine to print averages periodically
	go func() {
		ticker := time.NewTicker(interval)
		for range ticker.C {
			statsMutex.Lock()
			for ticker, stat := range stats {
				if stat.Count > 0 {
					avg := stat.Sum / float64(stat.Count)
					fmt.Printf("%s: Average Price = %.2f (from %d updates)\n", ticker, avg, stat.Count)
					// Reset stats after printing
					stat.Sum = 0
					stat.Count = 0
				}
			}
			statsMutex.Unlock()
		}
	}()

	// Main goroutine to process incoming stock data
	for stock := range stockChan {
		statsMutex.Lock()
		if _, exists := stats[stock.Ticker]; !exists {
			stats[stock.Ticker] = &StockStats{}
		}
		stats[stock.Ticker].Sum += stock.Price
		stats[stock.Ticker].Count++
		statsMutex.Unlock()
	}
}

