        EmailQueue {
            queue: VecDeque::new(),
        }
    }

    fn enqueue(&mut self, email: EmailTask) {
        self.queue.push_back(email);
    }

    fn process_next(&mut self) -> Option<String> {
        if let Some(email) = self.queue.pop_front() {
            let timestamp = SystemTime::now()
                .duration_since(UNIX_EPOCH)
                .unwrap()
                .as_secs();
            let log = format!(
                "[{}] Processed email: {} (Urgent: {})",
                timestamp, email.content, email.is_urgent
            );
            Some(log)
        } else {
            None
        }
    }

    fn shuffle_for_urgent(&mut self) {
        let mut urgent_emails: Vec<EmailTask> = self.queue
            .drain_filter(|email| email.is_urgent)
            .collect();

        let mut remaining_emails: Vec<EmailTask> = self.queue.drain(..).collect();

        urgent_emails.extend(remaining_emails);
        self.queue.extend(urgent_emails);
    }
}

