package main

import (
	"bytes"
	"sync"
	"time"
)

type EventLogger struct {
	buffer    bytes.Buffer
	mu        sync.Mutex
	batchSize int
	flushInt  time.Duration
	stopChan  chan struct{}
}

func NewEventLogger(batchSize int, flushInterval time.Duration) *EventLogger {
	return &EventLogger{
		batchSize: batchSize,
		flushInt:  flushInterval,
		stopChan:  make(chan struct{}),
	}
}

func (el *EventLogger) logEvents(event string) {
	el.mu.Lock()
	defer el.mu.Unlock()

	el.buffer.WriteString(event + "\n")

	if el.buffer.Len() >= el.batchSize {
		el.flush()
	}
}

func (el *EventLogger) flush() {
	if el.buffer.Len() == 0 {
		return
	}
	// Process the buffered events here (e.g., send to storage/API)
	el.buffer.Reset()
}

func (el *EventLogger) StartPeriodicFlush() {
	ticker := time.NewTicker(el.flushInt)
	go func() {
		for {
			select {
			case <-ticker.C:
				el.mu.Lock()
				el.flush()
				el.mu.Unlock()
			case <-el.stopChan:
				ticker.Stop()
				return
			}
		}
	}()
}

func (el *EventLogger) Stop() {
	close(el.stopChan)
	el.mu.Lock()
	el.flush()
	el.mu.Unlock()
}
