        return a.timestamp < b.timestamp;
    });

    // Merge duplicates
    std::deque<LogEntry> mergedLogs;
    for (const auto& log : logs) {
        if (!mergedLogs.empty() && mergedLogs.back().timestamp == log.timestamp) {
            // Merge content if timestamp is duplicate
