    mismatches = 0
    differences = []

    for i in range(max(len(seq1), len(seq2))):
        if i < len(seq1) and i < len(seq2):
            if seq1[i] == seq2[i]:
                matches += 1
            else:
                mismatches += 1
                differences.append((i, seq1[i], seq2[i]))
        else:
            mismatches += 1
            if i >= len(seq1):
                differences.append((i, None, seq2[i]))
            else:
