import java.util.HashMap;
import java.util.Arrays;

public class AnagramDetector {
    public static HashMap<String, Integer> detectAnagramOccurrences(String articleText, String[] words) {
        HashMap<String, Integer> result = new HashMap<>();
        HashMap<String, Integer> articleAnagramCounts = new HashMap<>();

        // Preprocess the article text: split into words, normalize, and count anagram signatures
        String[] articleWords = articleText.split("\\s+");
        for (String word : articleWords) {
            String normalized = normalizeWord(word);
            if (!normalized.isEmpty()) {
                String signature = getAnagramSignature(normalized);
                articleAnagramCounts.put(signature, articleAnagramCounts.getOrDefault(signature, 0) + 1);
            }
        }

        // Check each provided word against the article's anagram counts
        for (String word : words) {
            String normalized = normalizeWord(word);
            String signature = getAnagramSignature(normalized);
            result.put(word, articleAnagramCounts.getOrDefault(signature, 0));
        }

        return result;
    }

    private static String normalizeWord(String word) {
        return word.replaceAll("[^a-zA-Z]", "").toLowerCase();
    }

    private static String getAnagramSignature(String word) {
        char[] chars = word.toCharArray();
        Arrays.sort(chars);
        return new String(chars);
    }
}
