#include <vector>

std::vector<double> computeRollingAverages(const std::vector<double>& temperatures, int windowSize) {
    std::vector<double> averages;
    int n = temperatures.size();
    if (n == 0 || windowSize <= 0) return averages;

    for (int i = 0; i < n; ++i) {
        int start = std::max(0, i - windowSize / 2);
        int end = std::min(n - 1, i + windowSize / 2);
        double sum = 0.0;
        int count = 0;

        for (int j = start; j <= end; ++j) {
            sum += temperatures[j];
            count++;
        }
        averages.push_back(sum / count);
    }

    return averages;
}
