use std::collections::{HashSet, HashMap};

fn detect_cycle_in_graph(graph: &HashMap<u32, Vec<u32>>) -> bool {
    fn dfs(
        node: u32,
        graph: &HashMap<u32, Vec<u32>>,
        visited: &mut HashSet<u32>,
        recursion_stack: &mut HashSet<u32>,
    ) -> bool {
        if recursion_stack.contains(&node) {
            return true;
        }
        if visited.contains(&node) {
            return false;
        }

        visited.insert(node);
        recursion_stack.insert(node);

        if let Some(neighbors) = graph.get(&node) {
            for &neighbor in neighbors {
                if dfs(neighbor, graph, visited, recursion_stack) {
                    return true;
                }
            }
        }

        recursion_stack.remove(&node);
        false
    }

    let mut visited = HashSet::new();
    let mut recursion_stack = HashSet::new();

    for &node in graph.keys() {
        if dfs(node, graph, &mut visited, &mut recursion_stack) {
            return true;
        }
    }

    false
}
